def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    term = ((ratio - a)**6) / (a*b*1.1 + 2)
                    trig = np.cos(ratio * b / (a + 2)) + np.sin(ratio * a / (b + 1))
                    priority += np.power(term * trig, 1.3)
            priority += np.exp(ratio - 10) * np.cos(ratio * 0.9) ** 2.5
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * 3
            else:
                priority -= np.sqrt(bin_cap) * 1.7
        elif 6 < ratio <= 10:
            for m in range(1, 8):
                for n in range(1, m + 3):
                    x = ((ratio - m) ** 4) * np.sin(ratio * n * 1.3) / (n + 1)
                    y = np.tanh(x) * (m * 0.5)
                    priority += y
            priority += np.log(ratio) * 8 - np.tanh(ratio - 6) * 3
            priority *= np.cos(ratio / 2)
        elif 3 <= ratio <= 6:
            acc = 0
            for p in range(1, 15):
                acc += ((ratio - 3) ** p) / (p * 2) * np.sin(p * ratio)
            priority = acc * np.cos(5 * ratio) - np.log(ratio) * 7 + np.tanh(2 * (6 - ratio)) * 2
            if bin_cap < item * 1.5:
                priority += np.sqrt(item * bin_cap) * 1.3
            else:
                priority -= np.power(bin_cap / item, 0.5)
        elif 1 <= ratio < 3:
            s1 = 0
            s2 = 0
            for q in range(1, 20):
                s1 += ((3 - ratio) ** q) / (q ** 1.5 + 1) * np.cos(q * ratio * 1.3)
                if q % 2 == 0:
                    s2 += np.sin(q * ratio / (i + 1)) / (q + 1)
            priority = s1 + s2 - np.log1p(ratio) * 4
            if bin_cap > item * 2:
                priority -= np.exp(-ratio) * 5
            else:
                priority += np.tanh(bin_cap / (item + 0.1)) * 3
        elif 0.5 <= ratio < 1:
            s = 0
            for r in range(1, 25):
                power = ((1 - ratio) ** r) / (r + 1)
                s += power * np.sin(r * ratio * 2) * np.cos(r * i * 0.7)
            priority = s + np.exp(-bin_cap / (item + 0.5)) * 4
            if (i + int(item)) % 5 == 0:
                priority *= np.sqrt(bin_cap + 2) * 0.8
            else:
                priority /= (np.log1p(bin_cap) + 1)
        elif 0.2 <= ratio < 0.5:
            acc = 0
            for s in range(1, 18):
                acc += ((0.5 - ratio) ** s) / (s ** 2) * np.cos(s * item * 1.7)
            priority = acc * np.log1p(bin_cap) - 1 / (bin_cap + 4)
            if bin_cap < item * 0.4:
                priority += np.exp(-ratio * 2) * 3
            else:
                priority -= np.sqrt(item / (bin_cap + 0.1)) * 2
            for t in range(1, 6):
                priority += np.sin(ratio * t * i) / (t + 0.5)
        else:
            val = 0
            for u in range(1, 15):
                val += ((0.2 - ratio) ** u) / (u * 3.5) * np.sin(u * item * 1.1)
            priority = val + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.3
            else:
                priority /= 2.2
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 6) * np.cos(item * v * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.3
            for w in range(1, 5):
                priority += np.sin(ratio * w * i) * (0.7 ** w)
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            for z in range(1, 4):
                priority -= np.cos(ratio * (i + z) * 1.2) * 0.4
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.25
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
            priority += np.cos(ratio * i * 0.5) * 0.4
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
            priority -= np.sin(ratio * i * 0.5) * 0.4
        priorities[i] = priority
    return priorities
